"""SQLAlchemy ORM models — generated by doql."""
from sqlalchemy import Column, String, Integer, Float, Boolean, Text, Date, DateTime, JSON, ForeignKey
from sqlalchemy.orm import relationship
from database import Base


class Contact(Base):
    __tablename__ = "contacts"

    id = Column(String(36), primary_key=True)
    first_name = Column(String(255))
    last_name = Column(String(255))
    email = Column(String(255), unique=True, nullable=True)
    phone = Column(String(255), nullable=True)
    company = Column(String(255), nullable=True)
    position = Column(String(255), nullable=True)
    tags = Column(JSON, nullable=True)
    notes = Column(Text, nullable=True)
    source = Column(String(255), nullable=True)
    created = Column(DateTime, nullable=True)
    updated = Column(DateTime, nullable=True)


class Company(Base):
    __tablename__ = "companys"

    id = Column(String(36), primary_key=True)
    name = Column(String(255), unique=True)
    domain = Column(String(255), nullable=True)
    industry = Column(String(255), nullable=True)
    size = Column(String(255), nullable=True)
    website = Column(String(255), nullable=True)
    address = Column(JSON, nullable=True)
    created = Column(DateTime, nullable=True)


class Deal(Base):
    __tablename__ = "deals"

    id = Column(String(36), primary_key=True)
    title = Column(String(255))
    contact = Column(String(255))
    company = Column(String(255), nullable=True)
    value = Column(String(255), nullable=True)
    currency = Column(String(255), nullable=True)
    stage = Column(String(255), nullable=True)
    probability = Column(Integer, nullable=True, default=0)
    expected_close = Column(Date, nullable=True)
    assigned_to = Column(String(255), nullable=True)
    notes = Column(Text, nullable=True)
    created = Column(DateTime, nullable=True)
    updated = Column(DateTime, nullable=True)


class Activity(Base):
    __tablename__ = "activitys"

    id = Column(String(36), primary_key=True)
    type_ = Column(String(255))
    contact = Column(String(255), nullable=True)
    deal = Column(String(255), nullable=True)
    subject = Column(String(255))
    description = Column(Text, nullable=True)
    due_date = Column(DateTime, nullable=True)
    completed = Column(Boolean, nullable=True, default=False)
    assigned_to = Column(String(255), nullable=True)
    created = Column(DateTime, nullable=True)
